const page = $input.first().json;
const title = page.properties?.['タイトル']?.title?.[0]?.text?.content || 'No Title';
const type = page.properties?.['種別']?.select?.name || 'その他';
const detail = page.properties?.['詳細']?.rich_text?.[0]?.text?.content || '';
const sender = page.properties?.['送信者']?.rich_text?.[0]?.text?.content || 'anonymous';
const urgency = page.properties?.['緊急度']?.select?.name || 'medium';
const project = page.properties?.['対象プロジェクト']?.select?.name || 'shogun';
const ts = new Date().toISOString();
const shortId = Math.random().toString(36).substr(2, 8);
const id = `feedback_${ts.replace(/[-:T.Z]/g,'').substr(0,15)}_${shortId}`;
return [{ json: { id, timestamp: ts, sender, feedbackType: type, title, detail, urgency, project, pageId: page.id } }];

const { execSync } = require('child_process');
const os = require('os');
const path = require('path');
const fs = require('fs');

const data = $input.first().json;
const dataStr = JSON.stringify(data);

// Write to temp file to avoid shell injection
const tmpFile = path.join(os.tmpdir(), `feedback_${Date.now()}_${Math.random().toString(36).substr(2,6)}.json`);
fs.writeFileSync(tmpFile, dataStr, 'utf8');

try {
  const result = execSync(`python3 /home/ubuntu/shogun/scripts/n8n_feedback_append.py < "${tmpFile}"`, {
    encoding: 'utf-8',
    timeout: 15000
  });
  return [{ json: { success: true, output: result.trim(), id: data.id } }];
} finally {
  try { fs.unlinkSync(tmpFile); } catch(e) {}
}

const { execSync } = require('child_process');
const errMsg = ($json.execution?.error?.message || $json.error || 'unknown error').replace(/'/g, '');
try {
  execSync(`bash /home/ubuntu/shogun/scripts/ntfy.sh "[vps] feedback-system error: ${errMsg.substr(0,80)}" "n8n" "error"`, {
    encoding: 'utf-8',
    timeout: 10000
  });
} catch(e) {
  // best effort
}
return [{ json: $input.first().json }];

